using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext SeedStudents(this SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedDepartments(this SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 100000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 1 } },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 200000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 2 } }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedInstructors(this SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { ID = 10, LastName = "Kapoor", FirstMidName = "Candace", HireDate = new DateTime(2015, 1, 1), CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() },
                new Instructor { ID = 11, LastName = "Zheng", FirstMidName = "Roger", HireDate = new DateTime(2016, 1, 1), CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedCourses(this SchoolContext context)
        {
            if (!context.Departments.Any())
            {
                context.Departments.Add(new Department { DepartmentID = 1, Name = "English", Budget = 100000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 1 } });
                context.SaveChanges();
            }

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedAll(this SchoolContext context)
        {
            context.SeedInstructors();
            context.SeedDepartments();
            context.SeedCourses();
            context.SeedStudents();

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 1, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 2, Grade = Grade.C }
            );
            context.SaveChanges();
            return context;
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            using var service = new NotificationService();

            service.SendNotification("Course", "42", EntityOperation.UPDATE, "user1");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUser_IsSystem()
        {
            using var service = new NotificationService();

            service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            using var service = new NotificationService();
            // Drain the static queue
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_MultipleMessages_DequeuedInOrder()
        {
            using var service = new NotificationService();
            // Drain queue first
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void GenerateMessage_CreateOperation_ContainsCreated()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("created", notification!.Message);
        }

        [Fact]
        public void GenerateMessage_UpdateOperation_ContainsUpdated()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("updated", notification!.Message);
        }

        [Fact]
        public void GenerateMessage_DeleteOperation_ContainsDeleted()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.Contains("deleted", notification!.Message);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            using var service = new NotificationService();
            // Should not throw (no-op implementation)
            service.MarkAsRead(999);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose(); // Should not throw
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextHelper.CreateContext();
            _context.SeedStudents();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView_WithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsOrderedByDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal("Alexander", model[0].LastName); // 2020 is earliest
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsDescendingDate()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal("Anand", model[0].LastName); // 2022 is latest
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_SetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", 5) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_WithValidId_ReturnsStudent()
        {
            // Add enrollment data for the include
            _context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 0 });
            _context.Enrollments.Add(new Enrollment { EnrollmentID = 100, CourseID = 100, StudentID = 1 });
            _context.SaveChanges();

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateOutOfRange_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Old",
                FirstMidName = "Date",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "NoLast",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Updated",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            // Detach the existing tracked entity
            var existing = _context.Students.Local.FirstOrDefault(s => s.ID == 1);
            if (existing != null)
                _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

