using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_LastPage_HasFewerItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<string> { "a", "b", "c" };

            var result = new PaginatedList<string>(items, 15, 2, 5);

            Assert.Equal(3, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }
    }
}

using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext SeedStudents(this SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedDepartments(this SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 100000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 1 } },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 200000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 2 } }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedInstructors(this SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { ID = 10, LastName = "Kapoor", FirstMidName = "Candace", HireDate = new DateTime(2015, 1, 1), CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() },
                new Instructor { ID = 11, LastName = "Zheng", FirstMidName = "Roger", HireDate = new DateTime(2016, 1, 1), CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedCourses(this SchoolContext context)
        {
            if (!context.Departments.Any())
            {
                context.Departments.Add(new Department { DepartmentID = 1, Name = "English", Budget = 100000, StartDate = new DateTime(2020, 1, 1), RowVersion = new byte[] { 0, 0, 0, 1 } });
                context.SaveChanges();
            }

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedAll(this SchoolContext context)
        {
            context.SeedInstructors();
            context.SeedDepartments();
            context.SeedCourses();
            context.SeedStudents();

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 1, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 2, Grade = Grade.C }
            );
            context.SaveChanges();
            return context;
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            using var service = new NotificationService();

            service.SendNotification("Course", "42", EntityOperation.UPDATE, "user1");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUser_IsSystem()
        {
            using var service = new NotificationService();

            service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            using var service = new NotificationService();
            // Drain the static queue
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_MultipleMessages_DequeuedInOrder()
        {
            using var service = new NotificationService();
            // Drain queue first
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void GenerateMessage_CreateOperation_ContainsCreated()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("created", notification!.Message);
        }

        [Fact]
        public void GenerateMessage_UpdateOperation_ContainsUpdated()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.Contains("updated", notification!.Message);
        }

        [Fact]
        public void GenerateMessage_DeleteOperation_ContainsDeleted()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.Contains("deleted", notification!.Message);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            using var service = new NotificationService();
            // Should not throw (no-op implementation)
            service.MarkAsRead(999);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose(); // Should not throw
        }
    }
}

