        {
            using var context = TestDbContextHelper.CreateContext();
            var instructor = new Instructor { LastName = "O", FirstMidName = "A", HireDate = DateTime.Now, CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            var retrieved = context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal("O", retrieved.Instructor.LastName);
        }

        [Fact]
        public void Context_Notification_CanStore()
        {
            using var context = TestDbContextHelper.CreateContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "admin",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }

        [Fact]
        public void Context_Person_FullName_Property()
        {
            using var context = TestDbContextHelper.CreateContext();
            var student = new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Now };
