                new Instructor { ID = 11, LastName = "Zheng", FirstMidName = "Roger", HireDate = new DateTime(2016, 1, 1), CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext SeedCourses(this SchoolContext context)
        {
