using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextHelper.CreateContext();
            _context.SeedAll();
            // Add course assignments for instructor testing
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 1050 });
            _context.SaveChanges();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_NoParams_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.NotNull(model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var result = _controller.Index(10, null) as ViewResult;

            var model = result!.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            // Enrollments are already seeded for course 1050
            var result = _controller.Index(10, 1050) as ViewResult;

            var model = result!.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_WithValidId_ReturnsInstructor()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Kapoor", instructor.LastName);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            var selectedCourses = new[] { "1050" };

            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "NoLast",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsInstructor()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsInstructor()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Kapoor", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Add office assignment for full coverage
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 11, Location = "Room 101" });
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(11) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Instructors.Find(11));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Set instructor as department administrator
            var dept = _context.Departments.First();
            dept.InstructorID = 11;
            _context.SaveChanges();

            // Add office assignment since DeleteConfirmed includes it
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 11, Location = "Room 102" });
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(11) as RedirectToActionResult;

            Assert.NotNull(result);
            var updatedDept = _context.Departments.First();
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

