using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextHelper.CreateContext();
            var student = new Student
            {
                LastName = "TestStudent",
                FirstMidName = "First",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("TestStudent", retrieved.LastName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveCourse()
        {
            using var context = TestDbContextHelper.CreateContext();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 100, StartDate = DateTime.Now, RowVersion = new byte[] { 1 } });
            context.SaveChanges();

            var course = new Course { CourseID = 100, Title = "TestCourse", Credits = 3, DepartmentID = 1 };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.First();
            Assert.Equal("TestCourse", retrieved.Title);
        }

        [Fact]
        public void Context_CanAddAndRetrieveDepartment()
        {
            using var context = TestDbContextHelper.CreateContext();
            var dept = new Department
            {
                Name = "Physics",
                Budget = 50000,
                StartDate = new DateTime(2020, 1, 1),
                RowVersion = new byte[] { 1 }
            };

            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.First();
            Assert.Equal("Physics", retrieved.Name);
        }

        [Fact]
        public void Context_CanAddAndRetrieveInstructor()
        {
            using var context = TestDbContextHelper.CreateContext();
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("Smith", retrieved.LastName);
        }

        [Fact]
        public void Context_CanAddEnrollment_WithRelationships()
        {
            using var context = TestDbContextHelper.CreateContext();
            var student = new Student { LastName = "Test", FirstMidName = "S", EnrollmentDate = DateTime.Now };
            context.Students.Add(student);
            context.Departments.Add(new Department { DepartmentID = 1, Name = "D", Budget = 1, StartDate = DateTime.Now, RowVersion = new byte[] { 1 } });
            context.SaveChanges();

            var course = new Course { CourseID = 1, Title = "C", Credits = 3, DepartmentID = 1 };
            context.Courses.Add(course);
            context.SaveChanges();

            var enrollment = new Enrollment { CourseID = 1, StudentID = student.ID, Grade = Grade.A };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var retrieved = context.Enrollments.Include(e => e.Course).Include(e => e.Student).First();
            Assert.Equal("C", retrieved.Course.Title);
            Assert.Equal("Test", retrieved.Student.LastName);
        }

        [Fact]
        public void Context_CourseAssignment_CompositeKey()
        {
            using var context = TestDbContextHelper.CreateContext();
            var instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Now, CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() };
            context.Instructors.Add(instructor);
            context.Departments.Add(new Department { DepartmentID = 1, Name = "D", Budget = 1, StartDate = DateTime.Now, RowVersion = new byte[] { 1 } });
            context.SaveChanges();

            context.Courses.Add(new Course { CourseID = 1, Title = "C", Credits = 3, DepartmentID = 1 });
            context.SaveChanges();

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = 1 };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();

            var retrieved = context.CourseAssignments.First();
            Assert.Equal(instructor.ID, retrieved.InstructorID);
            Assert.Equal(1, retrieved.CourseID);
        }

        [Fact]
        public void Context_OfficeAssignment_OneToOne()
        {
            using var context = TestDbContextHelper.CreateContext();
            var instructor = new Instructor { LastName = "O", FirstMidName = "A", HireDate = DateTime.Now, CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            var retrieved = context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal("O", retrieved.Instructor.LastName);
        }

        [Fact]
        public void Context_Notification_CanStore()
        {
            using var context = TestDbContextHelper.CreateContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "admin",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }

        [Fact]
        public void Context_Person_FullName_Property()
        {
            using var context = TestDbContextHelper.CreateContext();
            var student = new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Now };
            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Doe, Jane", retrieved.FullName);
        }

        [Fact]
        public void Context_DeleteStudent_RemovesFromDb()
        {
            using var context = TestDbContextHelper.CreateContext();
            var student = new Student { LastName = "ToDelete", FirstMidName = "X", EnrollmentDate = DateTime.Now };
            context.Students.Add(student);
            context.SaveChanges();

            context.Students.Remove(student);
            context.SaveChanges();

            Assert.Empty(context.Students);
        }
    }
}

